{attribute 'pack_mode' := '4'} TYPE HoldingRegs : STRUCT // ============================================================= // Модули M7–M9 (MDS AO-2UI) - Управление клапанами (Выходы 4-20мА) // =============================================================
// --- Управление запорно-регулирующими клапанами (задание 0..100%) --- AO1_CmdValveDiazo : REAL; // 101. Управление клапаном диазосоединения AO2_CmdValveSoda : REAL; // 103. Управление клапаном едкого натра 14% AO3_CmdValveSteam : REAL; // 105. Управление клапаном пара 6 ати
// --- Уставки с панели (ручной режим) --- rValveManSet_Diazo : REAL := 0.0; // 107. Уставка с панели: Диазо rValveManSet_Soda : REAL := 0.0; // 109. Уставка с панели: Сода rValveManSet_Steam : REAL := 0.0; // 111. Уставка с панели: Пар
// --- Переменные для автоматического управления (выходы ПИД-регуляторов) --- rAutoSet_Diazo : REAL; // 113. Выход ПИД расхода диазо rAutoSet_Soda : REAL; // 115. Выход ПИД расхода соды rAutoSet_Steam : REAL; // 117. Выход ПИД расхода пара
// --- Технологические уставки --- rWaterDose : REAL := 5.0; // 119. Заданная доза воды, м³ (5 кубов) rSetTempApp511 : REAL := 86.0; // 121. Уставка температуры rSetFlowDiazo_511 : REAL; // 123. Уставка мгновенного расхода диазосоединения (до 19 м³/ч) rSetPh_511 : REAL; // 125. Целевая уставка pH (9.5..12 ед.)
// --- Настройки алгоритма опустошения емкости (для наладчика) --- rZeroFlowThreshold_511 : REAL := 0.2; // 127. Порог падения расхода диазо (м³/ч), ниже которого считаем, что емкость пуста uiEmptyDelaySec_511 : UINT := 20; // 129. Задержка фиксации пустого трубопровода (сек)
// --- Настройки ПИД-регуляторов (для наладки контуров с HMI) --- rKp_Diazo_511 : REAL := 1.0; // 131. Пропорциональный коэффициент контура расхода диазосоединения rTn_Diazo_511 : REAL := 5.0; // 133. Время интегрирования контура расхода диазосоединения (сек) rKp_pH_511 : REAL := 2.0; // 135. Пропорциональный коэффициент контура pH rTn_pH_511 : REAL := 10.0; // 137. Время интегрирования контура pH (сек) rKp_Steam_511 : REAL := 2.0; // 139. Пропорциональный коэффициент контура пара (нагрева) rTn_Steam_511 : REAL := 15.0; // 141. Время интегрирования контура пара (сек) rTv_Steam_511 : REAL := 0.0; // 143. Время дифференцирования контура пара (сек)
END_STRUCT END_TYPE

