PROGRAM PLC_PRG // Antigravity Sync Test VAR fbElemerREM : fbElemerREM;
(* Переменные из вкладки Modbus Generic Serial Slave I/O Mapping *) Hmi_Flow_Regs AT %IW67 : ARRAY[0..1] OF WORD; (* Канал 0 (Мгновенный расход) *) Hmi_Volume_Regs AT %IW63 : ARRAY[0..3] OF WORD; (* Канал 1 (Накопленный объем) *) xModbusCommError : BOOL; (* Системный флаг ошибки связи с прибором *) xHmiResetCmd : BOOL; (* Сигнал сброса сумматора с HMI-панели *)
(* Выходные очищенные технологические переменные *) rCurrentFlowRate : REAL; (* Мгновенный расход в систему, куб.м/ч *) lrAccumulatedVol : LREAL; (* Точный накопленный объем, куб.м *) sOperatorMessage : STRING(255); (* Сообщение для текстовой строки на панели *)
