// ============================================================ // ПЕРЕМЕННЫЕ ДЛЯ ТЕСТИРОВАНИЯ И СИМУЛЯЦИИ СУММАТОРА // ============================================================ xSimEnable : BOOL := FALSE; (* Включить режим симуляции (True = подмена датчиков) *) rSimFlowSpeed : REAL := 20.0; (* Скорость потока при открытом клапане, куб.м/ч *) rSimTotalStorage : REAL := 125.45; (* Внутренний виртуальный накопительный счетчик куб.м *)
fbSimClock : TON; (* Генератор тактов времени для подсчета объема *) rDeltaVolume : REAL; (* Математический шаг приращения за 1 такт *) // ============================================================ END_VAR

