(*
* @fb: PRG_ModbusSlave_Sync
* @desc: Исправленная синхронизация через прямые указатели (устранение C0047/C0077)
*)
PROGRAM PRG_ModbusSlave_Sync
VAR
    fbSlv               : abakplcutils.MDB;
    sStatus             : STRING(255);

    // Вспомогательные буферы
    wMbHolding          : ARRAY[0..500] OF WORD; 
    wOldMbHolding       : ARRAY[0..500] OF WORD; 

    // Указатели для работы со структурами GVL как с массивами
    pCurrWord           : POINTER TO WORD;
    pOldWord            : POINTER TO WORD;

    wIndex              : WORD;
    uiHoldRegsCnt       : WORD;
    uiInRegsCnt         : WORD;
    xFirstLoop          : BOOL := TRUE;

    C_INPUT_REG_START   : WORD := 1;
    C_HOLD_REG_START    : WORD := 1000;
END_VAR

ST.xhtml:
wIndex := 0;
pInputRegs := ADR(GVL.gInputRegs);

//WHILE wIndex < wInputRegsLength DO
	fbSlv.SetWordRegs (wInputRegsOffset +wIndex + 1 , pInputRegs, wInputRegsLength);	

	// INC
	//wIndex := wIndex + 1;
//	pInputRegs := pInputRegs + SIZEOF(WORD);
//END_WHILE;

wIndex :=0;
pHoldingRegs:= ADR(GVL.gHoldingRegs);
pMbHolding := ADR(wMbHolding);
pOldMbHoldingRegs:= ADR(wOldMbHoldingRegs);
pOldHoldingRegs	:= ADR(wOldHoldingRegs);

WHILE wIndex < wHoldingRegsLength DO

	wMbHolding[0]:= 0;
	wMbHolding[1]:= 0;	
	IF NOT bFirstLoop THEN
		fbSlv.SetWordRegs(wHoldingRegsOffset + wIndex + 1 , pMbHolding, 2);	
		MEMUtils.MemCpy(pbyDest := pOldMbHoldingRegs, pbySrc := pMbHolding, 4);
		MEMUtils.MemCpy(pbyDest := pOldHoldingRegs, pbySrc := pMbHolding, 4);	
	ELSE
		bIsGetMb := fbSlv.GetWordRegs(wHoldingRegsOffset  + wIndex + 1,  pMbHolding, 2);

		IF (NOT MEMUtils.MemCmp(pOldHoldingRegs, pHoldingRegs,4)) THEN

			MEMUtils.MemCpy(pbyDest := pMbHolding, pbySrc := pHoldingRegs, 4);
			fbSlv.SetWordRegs(wHoldingRegsOffset + wIndex + 1 , pMbHolding, 2);	

		ELSIF (NOT MEMUtils.MemCmp(pOldMbHoldingRegs, pMbHolding,4)) THEN

			MEMUtils.MemCpy(pbyDest := pHoldingRegs, pbySrc := pMbHolding, 4);
		END_IF

		MEMUtils.MemCpy(pbyDest := pOldMbHoldingRegs, pbySrc := pMbHolding, 4);
		MEMUtils.MemCpy(pbyDest := pOldHoldingRegs, pbySrc := pHoldingRegs, 4);
	END_IF
	// INC		
 	wIndex := wIndex + 2;

	pOldMbHoldingRegs:= pOldMbHoldingRegs + 4;
	pOldHoldingRegs:= pOldHoldingRegs + 4;
    pHoldingRegs := pHoldingRegs + 4;
END_WHILE;

wIndex := 0;
pInputs := ADR(GVL.gInputs);

WHILE wIndex < wInputsLength DO
	bMbCoil[0] := pInputs^;
	fbSlv.SetCoil(wInputsOffset + wIndex + 1 , pInputs^);	

	// INC
	wIndex := wIndex + 1;
	pInputs := pInputs + SIZEOF(BOOL);
END_WHILE;

wIndex := 0;
pCoils := ADR(GVL.gCoils);

pMbCoil := ADR(bMbCoil);
pOldMbCoils:= ADR(bOldMbCoils);
pOldCoils	:= ADR(bOldCoils);

WHILE wIndex < wCoilsLength DO
	IF NOT bFirstLoop THEN
		pMbCoil^:=FALSE;
		fbSlv.SetCoil(wCoilsOffset  + wIndex + 1 , pMbCoil^);
		MEMUtils.MemCpy(pbyDest := pOldMBCoils, pbySrc := pMbCoil, 1);
		MEMUtils.MemCpy(pbyDest := pOldCoils, pbySrc := pMbCoil, 1);	
	ELSE

		pMbCoil^ := fbSlv.GetCoil(wCoilsOffset  + wIndex + 1);

		IF (NOT MEMUtils.MemCmp(pOldCoils, pCoils, 1)) THEN

			MEMUtils.MemCpy(pbyDest := pMbCoil, pbySrc := pCoils, 1);
			fbSlv.SetCoil(wCoilsOffset  + wIndex + 1 , pMbCoil^);	

		ELSIF (NOT MEMUtils.MemCmp(pOldMbCoils, pMbCoil, 1)) THEN

			MEMUtils.MemCpy(pbyDest := pCoils, pbySrc := pMbCoil, 1);
		END_IF

		MEMUtils.MemCpy(pbyDest := pOldMBCoils, pbySrc := pMbCoil, 1);
		MEMUtils.MemCpy(pbyDest := pOldCoils, pbySrc := pCoils, 1);
	END_IF
	// INC		
 	wIndex := wIndex + 1;

	pOldMbCoils:= pOldCoils + 1;
	pOldCoils:= pOldCoils + 1;
    pCoils := pCoils + 1;
END_WHILE;

IF NOT bFirstLoop THEN
	fbSlv.IsVirtualModbus := 0;

	GVL.gInputRegs.INPUTREGS := SIZEOF(GVL.gInputRegs)/2;
	GVL.gInputRegs.HOLDINGS := SIZEOF(GVL.gHoldingRegs)/2;
	GVL.gInputRegs.INPUTS := SIZEOF(GVL.gInputs);
	GVL.gInputRegs.COILS := SIZEOF(GVL.gCoils);

	MBS_HoldingRegs_Change();
	MBS_Coils_Change();

	GVL.gHoldingRegs :=PVL.rHoldingRegs;
	bFirstLoop := TRUE;
ELSE
	MBS_HoldingRegs_Change();
	MBS_Coils_Change();

	MBS_InputRegs_WRITE();
	MBS_Inputs_WRITE();
	PVL.rHoldingRegs :=GVL.gHoldingRegs;
END_IF

