ST.xhtml:
// 1. Проверка инициализации основного выходного указателя
IF pOutReal = 0 THEN
    xError := TRUE;
    sStatus := 'ОШИБКА: Целевой адрес OutReal не назначен!';
    RETURN; // Прекращаем выполнение, чтобы не вызвать исключение
END_IF

// 2. Выбор источника данных в зависимости от режима
IF xModeManual THEN
    // Режим РУЧНОЙ
    IF pSetMan <> 0 THEN
        rActualSetpoint := pSetMan^;
        xError := FALSE;
        IF xEnableLog THEN sStatus := 'Режим: РУЧНОЙ. Уставка с HMI.'; END_IF
    ELSE
        xError := TRUE;
        sStatus := 'Ошибка: Пустой указатель на ручную уставку!';
    END_IF
ELSE
    // Режим АВТО
    IF pSetAuto <> 0 THEN
        rActualSetpoint := pSetAuto^;
        xError := FALSE;
        IF xEnableLog THEN sStatus := 'Режим: АВТО. Управление от ПЛК.'; END_IF
    ELSE
        xError := TRUE;
        sStatus := 'Ошибка: Пустой указатель на авто-уставку!';
    END_IF
END_IF

// 3. Обработка ТАУ (ограничение диапазона)
rActualSetpoint := LIMIT(rMinLimit, rActualSetpoint, rMaxLimit);

// 4. Прямая запись в память по адресу, если нет ошибок
IF NOT xError THEN
    pOutReal^ := rActualSetpoint;
END_IF

pSetMan  := pManualVar;
pSetAuto := pAutoVar;
pOutReal := pOutputVar;

Init := (pSetMan <> 0 AND pSetAuto <> 0 AND pOutReal <> 0);

// 1. Проверка на нулевой указатель и деление на ноль
IF pOutput = 0 OR (X2 = X1) THEN
    FC_Write_AO := FALSE;
    RETURN;
END_IF;

// 2. Линейное масштабирование (из входного диапазона в 4..20мА)
TMP := (Y2 - Y1) / (X2 - X1) * (VAL_IN - X1) + Y1;

// 3. Преобразование REAL во внутреннее битовое представление DWORD
dwValue := OSCAT_BASIC.REAL_TO_DW(TMP);

// 4. Запись напрямую в память по указателю (разбивка на 2 WORD)
// В ПЛК Абак обычно старшее слово идет первым (зависит от настроек модуля)
pOutput^[0] := OSCAT_BASIC.WORD_OF_DWORD(dwValue, 1); // High Word
pOutput^[1] := OSCAT_BASIC.WORD_OF_DWORD(dwValue, 0); // Low Word

FC_Write_AO := TRUE;

// 1. Линейное масштабирование (Scale)
// Формула: Out = ((In - InMin) * (OutMax - OutMin) / (InMax - InMin)) + OutMin
IF (rInMax <> rInMin) THEN
    rScaled := ((rValIn - rInMin) * (rOutMax - rOutMin) / (rInMax - rInMin)) + rOutMin;
ELSE
    rScaled := rOutMin;
END_IF

// 2. Получаем битовое представление REAL как DWORD
pReal := ADR(rScaled);
dwRaw := pReal^;

// 3. Перепаковка в формат CDAB
// Исходный (ABCD): [Byte3][Byte2][Byte1][Byte0]
// Формат CDAB:     [Byte1][Byte0][Byte3][Byte2]
// То есть меняем местами слова (WORD)

dwCDAB := ROL(dwRaw, 16); // Простейший способ поменять слова местами

// 4. Запись результата по указателю
IF pOutput <> 0 THEN
    pOutput^[1] := DWORD_TO_WORD(dwCDAB AND 16#FFFF);        // Младшее слово CDAB (бывшее старшее AB)
    pOutput^[0] := DWORD_TO_WORD(SHR(dwCDAB, 16));           // Старшее слово CDAB (бывшее младшее CD)
    FC_Write_AO_CDAB := TRUE;
ELSE
    FC_Write_AO_CDAB := FALSE;
END_IF

