FUNCTION FC_Write_AO_CDAB : BOOL
VAR_INPUT
    rValIn   : REAL;    // Входная уставка (0..100)
    pOutput  : POINTER TO ARRAY[0..1] OF WORD; 
    rInMin   : REAL;    
    rInMax   : REAL;    
    rOutMin  : REAL;    
    rOutMax  : REAL;    
END_VAR
VAR
    rScaled  : REAL;
    dwRaw    : DWORD;
	dwCDAB: DWORD;
    pReal    : POINTER TO DWORD;
END_VAR

ST.xhtml:
TMP := OSCAT_BASIC.DW_TO_REAL(X:= OSCAT_BASIC.DWORD_OF_WORD(W1:= F_WORD_IN , W0:= S_WORD_IN ));
IF (RANGE_CONV)
THEN
	IF (TMP=9999 OR TMP=-9999 OR TMP=-7777 OR TMP=7777)
	THEN 
		VAL_OUT :=  TMP; 		
	ELSE
		VAL_OUT :=  (Y2 - Y1) / (X2 - X1) * (TMP - X1) + Y1;
	END_IF

ELSE
	VAL_OUT :=  TMP; 
END_IF

