ST.xhtml:
// Initialization: Clear buffer and add Measurement + Tag
// Format: "Measurement,TagKey=TagValue " (note the space at the end)
sBuffer := CONCAT(sMeasurement, ',');
sBuffer := CONCAT(sBuffer, sTagKey);
sBuffer := CONCAT(sBuffer, '=');
sBuffer := CONCAT(sBuffer, sTagValue);
sBuffer := CONCAT(sBuffer, ' '); // Line protocol space between tags and fields

iCurrentLen := LEN(sBuffer);

// Add comma if not the first field
IF iCurrentLen > (LEN(sMeasurement) + LEN(sTagKey) + LEN(sTagValue) + 3) THEN
    sFragment := ',';
ELSE
    sFragment := '';
END_IF

// Format: Key=Value
sFragment := CONCAT(sFragment, sName);
sFragment := CONCAT(sFragment, '=');
sFragment := CONCAT(sFragment, REAL_TO_STRING(rVal));

// Append to buffer using STU for safety or simple CONCAT
STU.StrConcatA(ADR(sFragment), ADR(sBuffer), SIZEOF(sBuffer));
iCurrentLen := LEN(sBuffer);
AddReal := TRUE;

