CASE eState OF	

	CLIENT_STATE.CREATE:	// создаем UDP-пира на заданном порту

		fbUdpPeer
		(
			xEnable		:= TRUE, 
			ipAddr		:= , 
			uiPort		:= ,
			ipMultiCast	:= ,  
		);

		IF fbUdpPeer.xActive THEN
			bStart := TRUE;
			eState	:= CLIENT_STATE.WAITING;
			influxIP.sAddr:=sIPInflux;
		ELSIF fbUdpPeer.xError THEN
			; // обработка ошибок
		END_IF

	CLIENT_STATE.WAITING:	// ожидаем команды на запись

		fbSendTrig(CLK:=blinker.OUT);

		IF fbSendTrig.Q THEN
// Calculate number of bytes to send
			sendData := sSendData;
			numberOfBytesToSend := DINT_TO_UDINT(Stu.StrLenA(ADR(sendData)));			

			eState	:= CLIENT_STATE.SEND;
		END_IF

	CLIENT_STATE.SEND:		// отправляем запрос серверу

			fbUdpSend
			(
				xExecute	:=	TRUE,
				udiTimeOut:= 1000, 
				hPeer		:=	fbUdpPeer.hPeer, 
				ipAddr:=  influxIP, 
				uiPort:= uiPortInflux, 
				szSize:= numberOfBytesToSend, 
				pData:= ADR(sendData), 
			);

			IF (fbUdpSend.xDone OR fbUdpSend.xError) THEN
				fbUdpSend(xExecute:=FALSE);
				eState	:= 	CLIENT_STATE.WAITING;
			END_IF

END_CASE

InterfaceAsPlainText.xhtml:
FUNCTION_BLOCK FB_ValveS_Compact
VAR_INPUT
    xMode        : BOOL; 
    xManControl  : BOOL; 
    xAutoControl : BOOL; 
END_VAR

VAR_OUTPUT
    xOutControl  : BOOL; 
END_VAR

ST.xhtml:
//==============================================================================
// Расчёт времени нахождения в текущем состоянии (в минутах для HMI)
//==============================================================================
tonStateTimer(IN := (eState = eLastState), PT := T#240h);
udiMinutesInState := TIME_TO_UDINT(tonStateTimer.ET) / 60000;

//==============================================================================
// 1. ДИАГНОСТИЧЕСКИЙ КОНТРОЛЬ АВАРИЙ СВЯЗИ ВЕРХНЕГО УРОВНЯ
//==============================================================================
IF xCommError THEN
    eState := E_REM_State.ERROR_COMM;
ELSIF xResetTotalizer AND eState <> E_REM_State.ERROR_COMM THEN
    eState := E_REM_State.RESET_LOGIC;
ELSIF eState <> E_REM_State.ERROR_COMM AND eState <> E_REM_State.RESET_LOGIC THEN
    eState := E_REM_State.OPERATING;
END_IF;

//==============================================================================
// 2. СТРУКТУРА СТЕЙТ-МАШИНЫ
//==============================================================================
CASE eState OF

    E_REM_State.INIT: //--------------------------------------------------------
        sStatus        := 'ЭЛЕМЕР-РЭМ: Ожидание первого скана и данных от Modbus-каналов';
        rInstantFlow   := DEVICE_DISCONNECTED;
        lrTotalVolume  := LREAL#-10000.0;
        xDataValid     := FALSE;

        IF pFlowBuffer <> 0 AND pVolumeBuffer <> 0 AND NOT xCommError THEN
            eState := E_REM_State.OPERATING;
        END_IF;


    E_REM_State.OPERATING: //---------------------------------------------------
        sStatus := 'ЭЛЕМЕР-РЭМ: Данные успешно обновляются, идёт технологический учёт';

        IF pFlowBuffer <> 0 AND pVolumeBuffer <> 0 THEN

            // ----------------------------------------------------------------
            // РАЗБОР МГНОВЕННОГО РАСХОДА F2
            // Канал 0, REAL 32 бита, формат прибора DCBA (Big-Endian)
            // Побайтовый разворот → Little-Endian ЦПУ ПЛК
            // ----------------------------------------------------------------
            pByteSrc := ADR(pFlowBuffer^[0]);
            pByteDst := ADR(dwRealParser);

            IF pByteSrc <> 0 AND pByteDst <> 0 THEN
                pByteDst[0] := pByteSrc[3]; // D → LSB
                pByteDst[1] := pByteSrc[2]; // C
                pByteDst[2] := pByteSrc[1]; // B
                pByteDst[3] := pByteSrc[0]; // A → MSB
                SysMemCpy(pDest := ADR(rInstantFlow), pSrc := ADR(dwRealParser), udiCount := SIZEOF(rInstantFlow));
            END_IF;


            // ----------------------------------------------------------------
            // РАЗБОР НАКОПЛЕННОГО ОБЪЁМА F1
            // Канал 1, Double/LREAL 64 бита, Big-Endian порядок WORD-регистров:
            //   src[0] = MSW (старший), src[3] = LSW (младший)
            //
            // Алгоритм прибора (из документации):
            //   v  = (uint64_t)src[0] << 48
            //   v |= (uint64_t)src[1] << 32
            //   v |= (uint64_t)src[2] << 16
            //   v |= (uint64_t)src[3]
            //
            // На Little-Endian ЦПУ ПЛК LREAL в памяти хранится так:
            //   pW[0] = LSW (биты  0..15)
            //   pW[1]        (биты 16..31)
            //   pW[2]        (биты 32..47)
            //   pW[3] = MSW (биты 48..63)
            //
            // Поэтому разворачиваем порядок WORD-ов:
            //   pW[3] := src[0]   (MSW прибора → старший WORD LREAL)
            //   pW[2] := src[1]
            //   pW[1] := src[2]
            //   pW[0] := src[3]   (LSW прибора → младший WORD LREAL)
            //
            // Байты ВНУТРИ каждого WORD НЕ трогаем — аппаратура ПЛК
            // уже прочитала их корректно в Little-Endian.
            // ----------------------------------------------------------------
            pWordDst := ADR(lrTotalVolume);

            IF pWordDst <> 0 THEN
                pWordDst[3] := pVolumeBuffer^[0]; // MSW прибора → старший WORD
                pWordDst[2] := pVolumeBuffer^[1];
                pWordDst[1] := pVolumeBuffer^[2];
                pWordDst[0] := pVolumeBuffer^[3]; // LSW прибора → младший WORD
            END_IF;


            // ----------------------------------------------------------------
            // ЗАЩИТА ТАУ: Валидация на NaN
            // ----------------------------------------------------------------
            IF rInstantFlow <> rInstantFlow OR lrTotalVolume <> lrTotalVolume THEN
                sStatus    := 'ЭЛЕМЕР-РЭМ: Критическая ошибка! Считано неопределённое значение NaN.';
                xDataValid := FALSE;
            ELSE
                xDataValid := TRUE;
            END_IF;

        ELSE
            sStatus    := 'ЭЛЕМЕР-РЭМ: Внимание, обнаружен нулевой указатель буферов опроса!';
            xDataValid := FALSE;
        END_IF;


    E_REM_State.RESET_LOGIC: //-------------------------------------------------
        sStatus    := 'ЭЛЕМЕР-РЭМ: Выполняется процедура сброса сумматора по команде оператора';
        xDataValid := TRUE;

        IF NOT xResetTotalizer THEN
            eState := E_REM_State.OPERATING;
        END_IF;


    E_REM_State.ERROR_COMM: //--------------------------------------------------
        sStatus       := 'АВАРИЯ связи: Прибор не отвечает. Проверьте кабель RS-485!';
        rInstantFlow  := DEVICE_DISCONNECTED;
        lrTotalVolume := LREAL#-10000.0;
        xDataValid    := FALSE;

        IF NOT xCommError THEN
            eState := E_REM_State.INIT;
        END_IF;

END_CASE;


//==============================================================================
// 3. ДИАГНОСТИЧЕСКОЕ ЛОГИРОВАНИЕ ДЛЯ ОПЕРАТОРА ПАНЕЛИ
//==============================================================================
IF xEnableLog AND (eState <> eLastState) THEN
    eLastState := eState;
    sStatus    := CONCAT(sStatus, CONCAT(' | Прошло времени: ', UDINT_TO_STRING(udiMinutesInState)));
    sStatus    := CONCAT(sStatus, ' мин.');
END_IF;

InterfaceAsPlainText.xhtml:
(* ИСПРАВЛЕНИЕ v4.1.0: - Исправлен разбор lrTotalVolume (LREAL / Double 64 бит). - Прибор передаёт регистры в порядке Big-Endian (src[0] = MSW, src[3] = LSW). - ЦПУ ПЛК — Little-Endian, поэтому выполняется разворот по WORD-словам: pW[3] = src[0] (старший), pW[0] = src[3] (младший). - Побайтовый подход заменён на пословный (POINTER TO WORD) — корректнее и безопаснее, так как каждый WORD внутри уже находится в правильном байтовом порядке аппаратуры Little-Endian. *)
FUNCTION_BLOCK fbElemerREM VAR_INPUT pFlowBuffer : POINTER TO ARRAY[0..1] OF WORD; (* Канал 0: Мгновенный расход F2, 2 регистра WORD *) pVolumeBuffer : POINTER TO ARRAY[0..3] OF WORD; (* Канал 1: Накопленный объём F1, 4 регистра WORD *) xCommError : BOOL; (* Признак ошибки связи (из статуса Modbus Slave) *) xEnableLog : BOOL := TRUE; (* Флаг разрешения детального логирования на HMI *) END_VAR VAR_IN_OUT xResetTotalizer : BOOL; (* Команда сброса сумматора с HMI — автосброс после выполнения *) END_VAR VAR_OUTPUT xDataValid : BOOL; (* Флаг достоверности данных для контуров ТАУ *) rInstantFlow : REAL; (* Мгновенный расход F2, куб.м/ч *) lrTotalVolume : LREAL; (* Накопленный общий объём F1, куб.м *) sStatus : STRING(255); (* Строка текущего шага для оператора панели *) END_VAR VAR (* Автомат состояний *) eState : E_REM_State; eLastState : E_REM_State;
(* Указатели для разбора REAL (32 бит) *) pByteSrc : POINTER TO BYTE; pByteDst : POINTER TO BYTE; dwRealParser : DWORD;
(* Указатель для разбора LREAL (64 бит) — пословный разворот *) pWordDst : POINTER TO WORD; (* Указатель на LREAL как массив из 4 WORD *)
(* Системные таймеры *) tonStateTimer : TON; udiMinutesInState : UDINT; END_VAR VAR CONSTANT DEVICE_DISCONNECTED : REAL := -10000.0; (* Маркер аварии датчика *) END_VAR

ST.xhtml:
pW    := ADR(lr);
pW[3] := pBuf^[0];
pW[2] := pBuf^[1];
pW[1] := pBuf^[2];
pW[0] := pBuf^[3];
F_ElemerREM_Volume := LREAL_TO_REAL(lr);

InterfaceAsPlainText.xhtml:
(*  Накопленный объём F1: 4 регистра WORD, Big-Endian Double → REAL  *)
FUNCTION F_ElemerREM_Volume : REAL
VAR_INPUT
    pBuf : POINTER TO ARRAY[0..3] OF WORD;
END_VAR
VAR
    lr   : LREAL;
    pW   : POINTER TO WORD;
END_VAR

ST.xhtml:
IF pBuf <> 0 THEN
    // Склеиваем два WORD в один DWORD (старшее слово сдвигаем на 16 бит влево)
    dw := SHL(WORD_TO_DWORD(pBuf^[0]), 16) OR WORD_TO_DWORD(pBuf^[1]);

    // Копируем память "бит-в-бит" из DWORD в REAL
    SysMemCpy(pDest := ADR(F_ElemerREM_Flow), pSrc := ADR(dw), udiCount := 4);
END_IF

// ----------------------------------------------------------------
// ФРОНТ OFF→ON : СТАРТ ДОЗИРОВАНИЯ
// ----------------------------------------------------------------
IF xStart AND NOT xLastStart THEN
    rStartVolume := rTotalVolume;
    rLoaded      := 0.0;
    xRunning     := TRUE;
    rStatus      := 1.0;
    xMode        := TRUE;   // переключаем клапан в авторежим
    xAutoControl := TRUE;   // открываем клапан
END_IF;

// ----------------------------------------------------------------
// РАБОЧИЙ ЦИКЛ: Считаем объем и проверяем достижение дозы
// ----------------------------------------------------------------
IF xRunning THEN
    rLoaded := rTotalVolume - rStartVolume;

    // Доза выполнена — предиктивное закрытие (Высший приоритет)
    IF rLoaded >= (rDose - rDeadband) THEN
        xAutoControl := FALSE;  // закрываем клапан
        xRunning     := FALSE;
        xStart       := FALSE;  // автосброс команды
        rStatus      := 2.0;    // DONE
    END_IF;
END_IF;

// ----------------------------------------------------------------
// ФРОНТ ON→OFF : ПРЕРЫВАНИЕ ОПЕРАТОРОМ
// (Сработает только если доза ЕЩЕ НЕ выполнена в этом цикле)
// ----------------------------------------------------------------
IF NOT xStart AND xLastStart AND xRunning THEN
    xRunning     := FALSE;
    xAutoControl := FALSE;  // закрываем клапан
    rStatus      := 3.0;    // ABORTED
END_IF;

// ----------------------------------------------------------------
// БУФЕР ФРОНТА (в конце скана)
// ----------------------------------------------------------------
xLastStart := xStart;

// --- ЛОГИКА ---

// 1. Управление режимами (детектирование изменения xEnable)
IF xEnable AND NOT xOldEnable THEN
    // ВКЛЮЧЕНИЕ:
    xStatusActive := TRUE;       // [2]
    xAutoModeCmd  := TRUE;       // Переводим внешний флаг в режим АВТО

ELSIF NOT xEnable AND xOldEnable THEN
    // ВЫКЛЮЧЕНИЕ:
    xStatusActive := FALSE;      // [2]
    xAutoModeCmd  := FALSE;      // Снимаем флаг АВТО (переход в ручной)
    rValveOut     := 0.0;        // Обнуляем выход на клапан [2]
END_IF;

xOldEnable := xEnable;

// 2. Вызов ПИД-регулятора
fbPID(
    ACT := rTempActual,          // [2]
    SET := rSetpoint,            // [2]
    MAN := NOT xStatusActive,    // Если не активен, ПИД в ручном режиме (MAN=TRUE) [2]
    RST := xReset,               // [2]
    KP  := rKp,                  // [2]
    TN  := MAX(rTn, 1.0),        // Защита от деления на 0, как в источнике [2]
    TV  := rTv,                  // [3]
    LL  := rLimitLow,            // [3]
    LH  := rLimitHigh            // [3]
);

// 3. Передача значения из ПИД во внешнюю переменную через IN_OUT
// Обновляем выход только если контур активен, чтобы не перебивать ручное управление при выключенном блоке
IF xStatusActive THEN
    rValveOut := fbPID.Y;        // [3]
END_IF;

// --- ВЫЗОВ БЛОКА ПОДДЕРЖАНИЯ ТЕМПЕРАТУРЫ АППАРАТА 511 ---

fbSteamControl_511(
    xEnable       := xEnableTempControl,          // Команда оператора на запуск контура
    rTempActual   := GVL.gInputRegs.rTempApp511,  // Текущая температура из аппарата 511 [3, 4]
    rSetpoint     := rTempSetpoint_511,           // Уставка температуры (до 100 °C) [5, 6]
    xReset        := xResetTempPID,               // Сброс ПИД
    rKp           := GVL.gHoldingRegs.rKp_Steam_511,
    rTn           := GVL.gHoldingRegs.rTn_Steam_511,
    rTv           := GVL.gHoldingRegs.rTv_Steam_511,
    rLimitLow     := 0.0,
    rLimitHigh    := 100.0,

    // IN_OUT переменные (передаются по ссылке напрямую)
    rValveOut     := GVL.gHoldingRegs.rAutoSet_Steam, // Запись выхода ПИД в авто-задание клапана пара [1, 2]
    xAutoModeCmd  := xSteamAutoMode                   // Получаем команду режима от ФБ
);

// --- СИНХРОНИЗАЦИЯ РЕЖИМОВ УПРАВЛЕНИЯ ---
// Согласно вашей логике, клапан пара (fbValveSteam) работает в ручном режиме 
// когда GVL.gCoils.xManualMode_Steam = TRUE [2].
// Поскольку наш ФБ выдает TRUE для режима АВТО, нам нужно инвертировать этот сигнал:
GVL.gCoils.xManualMode_Steam := NOT xSteamAutoMode;

InterfaceAsPlainText.xhtml:
PROGRAM PRG_Apparatus511
VAR
    // Экземпляр функционального блока управления клапаном пара
    fbSteamControl_511 : FB_UniversalSteamValveControl;

    // Переменные для связи с HMI (если они еще не заданы в GVL)
    xEnableTempControl : BOOL;  // Команда с HMI: Включить автоматическое поддержание температуры
    rTempSetpoint_511  : REAL;  // Задание поддерживаемой температуры в аппарате (до 100 °C)
    xResetTempPID      : BOOL;  // Команда сброса ошибки ПИД-регулятора

    // Промежуточная переменная для связи флагов режима
    xSteamAutoMode     : BOOL;  // TRUE = АВТО, FALSE = РУЧНОЙ
END_VAR

ST.xhtml:
// --- 1. Обработка команд и переходов состояний ---
// Детектор переднего фронта запуска: если пришел сигнал Start
IF xStart AND NOT xOldStart THEN
    xActive    := TRUE;   // Начинаем нагрев
    xDone      := FALSE;  // Сбрасываем флаг готовности
    xEnablePID := TRUE;   // Разрешаем работу внутреннего регулятора
END_IF;

// Условие достижения температуры
IF xActive AND (rTempActual >= (rTargetTemp - rTolerance)) THEN
    xDone := TRUE;   // Сигнализируем успешное достижение уставки

    // Если НЕ нужно удерживать температуру, выключаем нагрев
    IF NOT xKeepTemp THEN
        xActive    := FALSE;  // Останавливаем процесс
        xEnablePID := FALSE;  // Отключаем ПИД-регулятор
    END_IF;
END_IF;

// Обработка ручного сброса / выключения
IF NOT xStart THEN
    xDone := FALSE; // Сбрасываем статус при снятии Start
    IF xActive THEN
        xActive    := FALSE;
        xEnablePID := FALSE;
    END_IF;
END_IF;

xOldStart := xStart; // Запоминаем состояние фронта

// --- 2. Вызов регулирующего функционального блока ---
fbSteamControl(
    xEnable       := xEnablePID,
    rTempActual   := rTempActual,
    rSetpoint     := rTargetTemp,
    xReset        := FALSE,
    rKp           := rKp,
    rTn           := rTn,
    rTv           := rTv,
    rLimitLow     := 0.0,
    rLimitHigh    := 100.0,
    rValveOut     := rValveOut,
    xAutoModeCmd  := xAutoModeCmd
);

// --- Автоматический нагрев аппарата 511 ---
fbAutoHeater511(
// --- Входы управления с HMI ---
xStart        := GVL.gCoils.xStartHeating_511,      // Признак запуска нагрева с панели оператора
xKeepTemp     := GVL.gCoils.xKeepTempHeating_511,   // TRUE = поддерживать температуру после достижения
rTargetTemp   := GVL.gHoldingRegs.rSetTempApp511,   // Уставка целевой температуры (до 100 °C)
// --- Технологические параметры ---
rTempActual   := GVL.gInputRegs.rTempApp511,        // Фактическая температура в емкости
rTolerance    := 0.5,                               // Допуск в градусах
// --- Настройки пид ---
rKp           := GVL.gHoldingRegs.rKp_Steam_511,
rTn           := GVL.gHoldingRegs.rTn_Steam_511,
rTv           := GVL.gHoldingRegs.rTv_Steam_511,
// --- Выходы на исполнительные механизмы (IN_OUT) ---
rValveOut     := GVL.gHoldingRegs.rAutoSet_Steam,   
xAutoModeCmd  := xSteamAutoMode
);

InterfaceAsPlainText.xhtml:
PROGRAM PRG_Apparatus511_Heating
VAR
    // Экземпляр нашего блока автоматического нагрева
    fbAutoHeater511 : FB_AutoHeater;

    // Вспомогательная переменная для связи флагов режима клапана
    xSteamAutoMode  : BOOL; 
END_VAR

ST.xhtml:
// --- ЛОГИКА БЛОКА ---

// 1. Детектор старта (Исправление №1: Явный сброс выходов при старте)
IF xStart AND NOT xOldStart THEN
    iState     := 1;    // Переход в RUNNING
    xActive    := TRUE; // Явное включение
    xDone      := FALSE;// Явный сброс готовности
    xNeedStop  := FALSE;// Явный сброс команды останова

    xAutoModeCmdDiazo := TRUE;
    xAutoModeCmdSoda  := TRUE;
END_IF;

// 2. Детектор прерывания оператором
IF NOT xStart AND xOldStart AND (iState = 1 OR iState = 2) THEN
    iState := 4; // Переход в ABORTED
    xNeedStop := TRUE;
END_IF;

// 3. Вызов таймера опустошения
// Таймер работает ТОЛЬКО когда мы находимся на шаге 2 (EMPTYING)
tonEmptyTimer(
    IN := (iState = 2), 
    PT := tEmptyDelay
);

// 4. КОНЕЧНЫЙ АВТОМАТ (STATE MACHINE)
CASE iState OF
    0: // --- IDLE (Ожидание) ---
        sStateStr  := 'ОЖИДАНИЕ: Аппарат готов к запуску';
        rStateCode := 0.0;
        xActive    := FALSE;
        xDone      := FALSE;
        rTimeLeft  := TIME_TO_REAL(tEmptyDelay) / 1000.0; 

    1: // --- RUNNING (Нормальное регулирование) ---
        sStateStr  := 'РАБОТА: Поддержание расхода и pH';
        rStateCode := 1.0;
        xActive    := TRUE;
        xDone      := FALSE;
        rTimeLeft  := TIME_TO_REAL(tEmptyDelay) / 1000.0;

        // Условие перехода: расход упал ниже порога
        IF rFlowDiazoActual <= rZeroFlowThreshold THEN
            iState := 2; 
        END_IF;

    2: // --- EMPTYING (Фиксация отсутствия расхода) ---
        sStateStr  := 'ВНИМАНИЕ: Падение расхода, отсчет времени...';
        rStateCode := 2.0;
        xActive    := TRUE;

        // Исправление №2: Безопасное вычитание времени (защита от переполнения/отрицательного результата)
        IF tonEmptyTimer.ET < tEmptyDelay THEN
            rTimeLeft := TIME_TO_REAL(tEmptyDelay - tonEmptyTimer.ET) / 1000.0;
        ELSE
            rTimeLeft := 0.0;
        END_IF;

        // Возврат в работу: если расход "ожил" (насос снова захватил жидкость)
        IF rFlowDiazoActual > rZeroFlowThreshold THEN
            iState := 1; 

        // Успешное завершение: таймер досчитал до конца
        ELSIF tonEmptyTimer.Q THEN
            iState := 3;
            xNeedStop := TRUE; // Даем команду на закрытие клапанов
        END_IF;

    3: // --- DONE (Успешное завершение) ---
        sStateStr  := 'ЗАВЕРШЕНО: Емкость диазосоединения пуста';
        rStateCode := 3.0;
        xActive    := FALSE;
        xDone      := TRUE;
        rTimeLeft  := 0.0;

        // Исправление №3: Защита от гонки состояний при быстром повторном старте
        IF NOT xStart AND NOT xOldStart THEN
            iState := 0;
        END_IF;

    4: // --- ABORTED (Прервано оператором) ---
        sStateStr  := 'ПРЕРВАНО: Остановка по команде оператора';
        rStateCode := 4.0;
        xActive    := FALSE;
        xDone      := FALSE;
        rTimeLeft  := 0.0;

        // Исправление №3: Защита от гонки состояний при быстром повторном старте
        IF NOT xStart AND NOT xOldStart THEN
            iState := 0;
        END_IF;

END_CASE;

// 5. Вызов ПИД-регуляторов (Работают только на активных шагах 1 и 2)
IF iState = 1 OR iState = 2 THEN
    fbPidFlowDiazo(
        ACT := rFlowDiazoActual, SET := rFlowDiazoSetpoint,
        MAN := FALSE, RST := FALSE, KP := rKp_Diazo, TN := MAX(rTn_Diazo, 1.0),
        TV := rTv_Diazo, LL := 0.0, LH := 100.0
    );
    rValveOutDiazo := fbPidFlowDiazo.Y;

    fbPidPh(
        ACT := rPhActual, SET := rPhSetpoint,
        MAN := FALSE, RST := FALSE, KP := rKp_pH, TN := MAX(rTn_pH, 1.0),
        TV := rTv_pH, LL := 0.0, LH := 100.0
    );
    rValveOutSoda := fbPidPh.Y;
END_IF;

// 6. Однократный безопасный останов
IF xNeedStop THEN
    // Сбрасываем интеграторы ПИД
    fbPidFlowDiazo(MAN := TRUE, SET := 0.0, ACT := 0.0, RST := TRUE);
    fbPidPh(MAN := TRUE, SET := 0.0, ACT := 0.0, RST := TRUE);

    // Закрываем клапаны и возвращаем в ручной режим
    rValveOutDiazo    := 0.0;
    xAutoModeCmdDiazo := FALSE;
    rValveOutSoda     := 0.0;
    xAutoModeCmdSoda  := FALSE;

    xNeedStop := FALSE; // Сбрасываем триггер останова
END_IF;

xOldStart := xStart;

InterfaceAsPlainText.xhtml:
FUNCTION_BLOCK FB_AutoCouplingDrainCascade
VAR_INPUT
    xStart             : BOOL;   // Триггер запуска стадии

    // --- Параметры Диазосоединения ---
    rFlowDiazoActual   : REAL;   // Текущий мгновенный расход диазо (м3/ч)
    rFlowDiazoSetpoint : REAL;   // Заданный мгновенный расход диазо

    // --- Параметры pH ---
    rPhActual          : REAL;   // Текущий pH (9.5..12 ед.)
    rPhSetpoint        : REAL;   // Уставка поддерживаемого pH

    // --- Условия завершения (Опустошение) ---
    rZeroFlowThreshold : REAL := 0.2;   // Порог "отсутствия расхода" (< 0.2 м3/ч)
    tEmptyDelay        : TIME := T#20S; // Время подтверждения отсутствия расхода

    // --- Настройки ПИД ---
    rKp_Diazo          : REAL := 1.0;
    rTn_Diazo          : REAL := 5.0;
    rTv_Diazo          : REAL := 0.0;
    rKp_pH             : REAL := 2.0;
    rTn_pH             : REAL := 10.0;
    rTv_pH             : REAL := 0.0;
END_VAR

VAR_IN_OUT
    rValveOutDiazo     : REAL;   // Задание на клапан диазо (0..100%)
    xAutoModeCmdDiazo  : BOOL;   // Режим АВТО для диазо
    rValveOutSoda      : REAL;   // Задание на клапан соды (0..100%)
    xAutoModeCmdSoda   : BOOL;   // Режим АВТО для соды
END_VAR

VAR_OUTPUT
    xActive            : BOOL;   // Стадия идет
    xDone              : BOOL;   // Стадия успешно завершена

    // --- Переменные для HMI ---
    rTimeLeft          : REAL;   // Оставшееся время до завершения (сек)
    rStateCode         : REAL;   // Код текущего состояния (0.0 .. 4.0)
    sStateStr          : STRING; // Текстовая расшифровка состояния
END_VAR

VAR
    fbPidFlowDiazo     : oscat_basic.CTRL_PID;
    fbPidPh            : oscat_basic.CTRL_PID;
    tonEmptyTimer      : TON;

    iState             : INT := 0; // Внутренний регистр шага State Machine
    xOldStart          : BOOL;
    xNeedStop          : BOOL;   // Флаг однократного останова оборудования
END_VAR

ST.xhtml:
// --- 1. ВЫЗОВ АЛГОРИТМА СЛИВА С ПОДДЕРЖАНИЕМ pH ---
fbCascadeDrain511(
    // Управление
    xStart             := GVL.gCoils.xStartCoupling_511,       

    // Параметры Диазосоединения
    rFlowDiazoActual   := GVL.gInputRegs.IR_FlowDiazo,         // Мгновенный расход [1]
    rFlowDiazoSetpoint := GVL.gHoldingRegs.rSetFlowDiazo_511,  // Уставка расхода [1]

    // Параметры pH
    rPhActual          := GVL.gInputRegs.rPhApp511,            // Показания pH-метра [1]
    rPhSetpoint        := GVL.gHoldingRegs.rSetPh_511,         // Целевая уставка pH [1]

    // Настройки условия завершения (конвертация UINT секунд в TIME)
    rZeroFlowThreshold := GVL.gHoldingRegs.rZeroFlowThreshold_511, 
    tEmptyDelay        := UDINT_TO_TIME(UINT_TO_UDINT(GVL.gHoldingRegs.uiEmptyDelaySec_511) * 1000), 

    // Настройки ПИД
    rKp_Diazo          := GVL.gHoldingRegs.rKp_Diazo_511,
    rTn_Diazo          := GVL.gHoldingRegs.rTn_Diazo_511,
    rKp_pH             := GVL.gHoldingRegs.rKp_pH_511,
    rTn_pH             := GVL.gHoldingRegs.rTn_pH_511,

    // Прямая связь с авто-заданиями физических клапанов (IN_OUT)
    rValveOutDiazo     := GVL.gHoldingRegs.rAutoSet_Diazo,     // [3]
    xAutoModeCmdDiazo  := xDiazoAutoMode,

    rValveOutSoda      := GVL.gHoldingRegs.rAutoSet_Soda,      // [3]
    xAutoModeCmdSoda   := xSodaAutoMode
);

// --- 2. СИНХРОНИЗАЦИЯ РЕЖИМОВ (Ручной/Авто) ---
// В физической логике клапанов TRUE = Ручной режим, поэтому инвертируем команду от блока
GVL.gCoils.xManualMode_Diazo := NOT xDiazoAutoMode;
GVL.gCoils.xManualMode_Soda  := NOT xSodaAutoMode;

// --- 3. ПЕРЕДАЧА СТАТУСОВ КОНЕЧНОГО АВТОМАТА НА HMI ---
// Булевые лампочки состояния процесса
GVL.gCoils.xCouplingActive_511 := fbCascadeDrain511.xActive; 
GVL.gCoils.xCouplingDone_511   := fbCascadeDrain511.xDone;   

// Числовые коды, оставшееся время и текст
GVL.gInputRegs.rTimeLeft_511   := fbCascadeDrain511.rTimeLeft;  // Оставшиеся секунды при падении расхода
GVL.gInputRegs.rStateCode_511  := fbCascadeDrain511.rStateCode; // 0.0, 1.0, 2.0, 3.0, 4.0
GVL.sStateStr_511              := fbCascadeDrain511.sStateStr;  // Расшифровка этапа

InterfaceAsPlainText.xhtml:
PROGRAM PRG_Apparatus511_CascadeDrain
VAR
    // Экземпляр последней версии блока (с конечным автоматом)
    fbCascadeDrain511 : FB_AutoCouplingDrainCascade;

    // Вспомогательные переменные для инверсии ручного/автоматического режимов
    xDiazoAutoMode    : BOOL;
    xSodaAutoMode     : BOOL;
END_VAR
